module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);
`define WIDTH 4'd4
`define COUNT 3'd3
  reg [2:0] cnt;
  reg valid;
  reg [3:0] data;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      cnt <= 3'd0;
    else if (cnt == `COUNT)
      cnt <= 3'd0;
    else
      cnt <= cnt + 1;
  end
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      valid <= 1'b0;
    else if (cnt == `COUNT)
      valid <= 1'b1;
    else
      valid <= 1'b0;
  end
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      data <= 4'd0;
    else if (cnt == `COUNT)
      data <= d;
    else
      data <= {data[2:0], data[3]};
  end
  assign dout = data[3];
  assign valid_out = valid;
endmodule
